import{_ as r,o as t,c as s,j as a,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"4.防具","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/1.生理类/超古代暗之巨人/4.防具.md","filePath":"4.资源分区/1.血统与训练/1.生理类/超古代暗之巨人/4.防具.md"}'),p={name:"4.资源分区/1.血统与训练/1.生理类/超古代暗之巨人/4.防具.md"};function _(d,e,l,i,c,b){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"_4-防具",tabindex:"-1"},[n("4.防具 "),a("a",{class:"header-anchor",href:"#_4-防具","aria-label":'Permalink to "4.防具"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调019")])])],-1),o('<h1 id="防具" tabindex="-1">防具 <a class="header-anchor" href="#防具" aria-label="Permalink to &quot;防具&quot;">​</a></h1><p>超古代肌肤护理<br> 分类：特异本质<br> 描述：超古代肌肤护理会如同重甲一样占据你的盔甲位，由于其本质你自身的皮肤，所以其提供的防御是天生防御，也不会带来外观上的改变。<br> 你可以穿戴其他服饰，但是身上带有的超古代巨人特有的刺青将无法隐藏。</p><p>特殊的，超古代肌肤护理是逐级购买的护甲，每个等级获得的效果将会保留计算。</p><p>第一疗程（D+500）<br> 奥式按摩：因为在光之巨人和怪兽的按摩（击打）和防卫军的温柔的护理（枪击）下你的身体得到了保养，你获得9点天生防御，获得了2点抵破甲和基于天生防御的【防弹】的特性。</p><p>第二疗程（C+1500）<br> 光子嫩肤：接受了接受了按摩以后怎么能不试试日光浴？在好心的光之巨人和防卫军的崭新科技下，你得到了很.好的“日光浴” （光线洗礼）护理，让你逐渐的放松起来。<br> 因为得到了护理，你的身体也进一 步的成长，体积增加6点（虚拟体积）。在上个等级获得的天生防御提升至17点，抵破甲提升至5，再获得基于天生防御的【免疫接触攻击】【防能量武器】特性。以及额外获得【自适应短休】。</p><p>第三疗程（B+2500）<br> 射线温泉：在经历了之前一系列的事情后，赶到战场的是太空纯天然射线温泉。<br> 因为你被放逐到宇宙里以石像的状态度过了千万年岁月，就算是温泉耐久仙人也比不过你。<br> 在纯天然的宇宙射线中，你的身体同样获得了一些增益，在之前等级获得的天生防御提高到24点，获得基于天生防御的【全伤害吸收1】【坚韧】（如果是达贡会提升为超级坚韧），以及1点快速医疗的恢复效果（医疗点12，可与主轴叠加），即使死后遗体也不会损坏。<br> 从现在开始，你可以使用运动+光线代替常规技能进行格挡，在血统中获得的变形效果来源等级提升至B级。（现在你的体型可在1-57体积间用自由动作切换）</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',8)])])}const f=r(p,[["render",_]]);export{m as __pageData,f as default};
